OUT_MD = Path(r"c:\Users\kasha\Downloads\بانک_سوالات_هوشبری_100_مرتب.md")
OUT_HTML = Path(r"c:\Users\kasha\Downloads\بانک_سوالات_هوشبری_100.html")
OUT_PDF = Path(r"c:\Users\kasha\Downloads\بانک_سوالات_هوشبری_100.pdf")

CHROME = Path(r"C:\Program Files\Google\Chrome\Application\chrome.exe")
EDGE = Path(r"C:\Program Files (x86)\Microsoft\Edge\Application\msedge.exe")


def apply_content_fixes(text: str) -> list[str]:
    """Apply medically/editorial fixes. Returns list of change descriptions."""
    changes: list[str] = []

    # 1) Q22 option 3: internally contradictory distractor
    old_q22 = (
        "۳) طولانی‌شدن اثر با کمبود سودوکولین‌استراز، منجر به بلوک کوتاه‌تر از حد انتظار"
    )
    new_q22 = (
        "۳) کاهش خطر هیپرکالمی در بیماران با سوختگی وسیع یا آسیب طناب نخاعی"
    )
    if old_q22 in text:
        text = text.replace(old_q22, new_q22)
        changes.append(
            "سؤال ۲۲، گزینه ۳: متن قبلی تناقض درونی داشت "
            "(«طولانی‌شدن اثر» و هم‌زمان «بلوک کوتاه‌تر»). "
            "گزینه نادرستِ واضح‌تری جایگزین شد تا با پاسخ صحیح (هیپرکالمی) تقابل آموزشی داشته باشد."
        )

    # 2) Terminology: standardize MH spelling
    if "هایپرترمی بدخیم" in text:
        text = text.replace("هایپرترمی بدخیم", "هیپرترمی بدخیم")
        changes.append(
            "اصطلاح «هایپرترمی بدخیم» به شکل استاندارد «هیپرترمی بدخیم» یکدست شد."
        )

    # 3) Terminology: neuroanesthesia spelling
    if "نوروآنستزی" in text:
        text = text.replace("نوروآنستزی", "نوروانستزی")
        changes.append(
            "املای «نوروآنستزی» به «نوروانستزی» یکدست شد."
        )

    # 4) Q45: earliest VAE monitor wording
    old_q45 = (
        "۲) افت ناگهانی ETCO2 (به دلیل شناسایی حساس با کاپنوگرافی و در صورت وجود، داپلر پره‌کوردیال)"
    )
    new_q45 = (
        "۲) افت ناگهانی ETCO2 (و در صورت وجود، تغییر/صدای غیرطبیعی در داپلر پره‌کوردیال که حساس‌تر است)"
    )
    if old_q45 in text:
        text = text.replace(old_q45, new_q45)
        # also refine explanation
        old_exp = (
            "**توضیح:** کاپنوگرافی و داپلر پره‌کوردیال از حساس‌ترین ابزارهای تشخیص زودهنگام آمبولی هوا هستند؛ "
            "افت ETCO2 معمولاً زودتر از تغییرات SpO2 رخ می‌دهد."
        )
        new_exp = (
            "**توضیح:** در میان مانیتورهای استاندارد، افت ناگهانی ETCO2 از نشانه‌های زودهنگام آمبولی هواست "
            "و معمولاً قبل از افت SpO2 دیده می‌شود. اگر داپلر پره‌کوردیال در دسترس باشد، اغلب حتی حساس‌تر "
            "و زودتر از کاپنوگرافی تغییر می‌کند."
        )
        if old_exp in text:
            text = text.replace(old_exp, new_exp)
        changes.append(
            "سؤال ۴۵: گزینه و توضیح اصلاح شد؛ داپلر پره‌کوردیال در صورت وجود معمولاً حساس‌تر از ETCO2 است، "
            "اما افت ETCO2 همچنان زودتر از SpO2 رخ می‌دهد."
        )

    # 5) Q43 explanation: clearer hydrostatic wording
    old_ibp = (
        "**توضیح:** قرارگیری ترانسدیوسر بالاتر از سطح قلب باعث ثبت فشار کاذباً پایین‌تر می‌شود، "
        "به دلیل ستون هیدرواستاتیک اضافی بین محل کاتتر و ترانسدیوسر."
    )
    new_ibp = (
        "**توضیح:** اگر ترانسدیوسر بالاتر از سطح قلب قرار گیرد، فشار ثبت‌شده کاذباً پایین‌تر از مقدار واقعی است "
        "(تقریباً حدود ۰٫۷۷ میلی‌متر جیوه به ازای هر سانتی‌متر اختلاف ارتفاع). "
        "بالعکس، ترانسدیوسر پایین‌تر از قلب فشار را کاذباً بالاتر نشان می‌دهد."
    )
    if old_ibp in text:
        text = text.replace(old_ibp, new_ibp)
        changes.append(
            "سؤال ۴۳: توضیح خطای ارتفاع ترانسدیوسر دقیق‌تر و کامل‌تر شد (اثر دوطرفه ارتفاع)."
        )

    # 6) Minor wording polish
    text = text.replace("شست‌وشوی نیتروژن", "شستشوی نیتروژن")
    if "شستشوی نیتروژن" in text:
        changes.append("سؤال ۲: املای «شست‌وشوی» به «شستشوی» اصلاح شد.")

    # 7) Clarify AHA source year note once at end if present
    # Keep AHA 2025 as-is (valid for mid-2026). Add brief disclaimer near sources in footer.

    return text, changes


def improve_structure(text: str) -> str:
    """Add TOC, usage note, and normalize spacing around questions."""
    # Normalize Windows newlines
    text = text.replace("\r\n", "\n").replace("\r", "\n")

    # Collapse 3+ blank lines
    text = re.sub(r"\n{3,}", "\n\n", text)

    # Ensure blank line before each question header
    text = re.sub(r"(?<!\n)\n(\*\*سؤال \d+)", r"\n\n\1", text)

    # Ensure blank line after --- separators
    text = re.sub(r"\n---\n(?!\n)", "\n---\n\n", text)

    header_extra = """# بانک ۱۰۰ سؤالی آمادگی آزمون صلاحیت حرفه‌ای کارشناس هوشبری

> **نسخه مرتب‌شده** — برای مرور بالینی و آمادگی آزمون. پاسخ و توضیح زیر هر سؤال آمده است.

## راهنمای استفاده
- هر سؤال شامل موضوع، سطح دشواری (آسان / متوسط / دشوار)، چهار گزینه، پاسخ صحیح، توضیح کوتاه و منبع است.
- ابتدا خودتان پاسخ دهید؛ سپس پاسخ و توضیح را بخوانید.
- در پایان، جدول جمع‌بندی مباحث پرتکرار برای مرور هدفمند آمده است.

## فهرست بخش‌ها
1. [راه هوایی، انتوباسیون، اکستوباسیون و راه هوایی دشوار](#بخش-۱-راه-هوایی-انتوباسیون-اکستوباسیون-و-راه-هوایی-دشوار-۱۷-سؤال) — ۱۷ سؤال
2. [داروهای بیهوشی، اپیوئیدها، شل‌کننده‌ها، آنتاگونیست‌ها، LAST و MH](#بخش-۲-داروهای-بیهوشی-اپیوئیدها-شل‌کننده‌ها-آنتاگونیست‌ها-last-و-mh-۲۰-سؤال) — ۲۰ سؤال
3. [مانیتورینگ، تجهیزات بیهوشی، سیستم تنفسی، ایمنی و عوارض حین عمل](#بخش-۳-مانیتورینگ-تجهیزات-بیهوشی-سیستم-تنفسی-ایمنی-و-عوارض-حین-عمل-۱۳-سؤال) — ۱۳ سؤال
4. [فیزیولوژی تنفسی و قلبی، ABG، ونتیلاتور، PEEP، ARDS، COPD و مایعات/خون](#بخش-۴-فیزیولوژی-تنفسی-و-قلبی-abg-ونتیلاتور-peep-ards-copd-و-مایعاتخون-۱۷-سؤال) — ۱۷ سؤال
5. [بی‌حسی نخاعی، اپیدورال، بلوک‌های منطقه‌ای و کنترل درد](#بخش-۵-بی‌حسی-نخاعی-اپیدورال-بلوک‌های-منطقه‌ای-و-کنترل-درد-۸-سؤال) — ۸ سؤال
6. [بیماران خاص و موقعیت‌های ویژه](#بخش-۶-بیهوشی-در-بارداری-کودکان-سالمندان-چاقی-بیماری-قلبی-کلیوی-کبدی-و-نوروانستزی-۱۲-سؤال) — ۱۲ سؤال
7. [ICU، شوک، سپسیس، الکترولیت، احیا، ROSC و اورژانس‌ها](#بخش-۷-icu-شوک-سپسیس-الکترولیت-احیا-rosc-و-اورژانس‌ها-۱۳-سؤال) — ۱۳ سؤال

---

"""

    # Remove original H1 and insert enhanced header before distribution table
    text = re.sub(r"^# بانک ۱۰۰ سؤالی.*?\n+", "", text, count=1, flags=re.M)

    # Rename section 6 heading slightly for clarity while keeping anchor-friendly text
    # Keep original heading; TOC already points to it.

    footer = """

---

## یادداشت ویرایش
- پاسخ‌ها بر اساس اصول استاندارد منابع ذکرشده تنظیم شده‌اند؛ جزئیات پروتکل ممکن است بر اساس مرکز درمانی متفاوت باشد.
- ارجاع به راهنماهای AHA مربوط به اصول کلی ALS است؛ برای آزمون رسمی، آخرین نسخهٔ مورد تأیید سازمان برگزارکننده را ملاک قرار دهید.
"""

    if "## یادداشت ویرایش" not in text:
        text = text.rstrip() + footer

    return header_extra + text.lstrip()


