def md_to_html(md_text: str) -> str:
    body = markdown.markdown(
        md_text,
        extensions=["tables", "fenced_code", "sane_lists", "toc"],
        output_format="html5",
    )
    # Soft-wrap question headers as visual cards via simple marker
    body = re.sub(
        r"<p><strong>(سؤال \d+ \| .*?)</strong></p>",
        r'<p class="q-head"><strong>\1</strong></p>',
        body,
    )
    css_extra = """
.q-head {
  background: #f5f9fc;
  border-right: 3px solid #2a7ab0;
  padding: 6px 10px;
  margin-top: 18px;
  page-break-after: avoid;
}
"""
    return f"""<!DOCTYPE html>
<html lang="fa" dir="rtl">
<head>
<meta charset="utf-8">
<title>بانک ۱۰۰ سؤالی آمادگی آزمون صلاحیت حرفه‌ای کارشناس هوشبری</title>
<style>{CSS}{css_extra}</style>
</head>
<body>
{body}
</body>
</html>
"""


def print_pdf(html_path: Path, pdf_path: Path) -> None:
    browser = CHROME if CHROME.exists() else EDGE
    if not browser.exists():
        raise RuntimeError("Chrome/Edge not found for PDF printing")

    # file URI for Windows
    html_uri = html_path.resolve().as_uri()
    cmd = [
        str(browser),
        "--headless=new",
        "--disable-gpu",
        "--no-pdf-header-footer",
        f"--print-to-pdf={pdf_path}",
        "--print-to-pdf-no-header",
        html_uri,
    ]
    subprocess.run(cmd, check=True, capture_output=True, text=True)


def main() -> None:
    raw = SRC.read_text(encoding="utf-8")
    fixed, changes = apply_content_fixes(raw)
    cleaned = improve_structure(fixed)

    OUT_MD.write_text(cleaned, encoding="utf-8")
    html = md_to_html(cleaned)
    OUT_HTML.write_text(html, encoding="utf-8")
    print_pdf(OUT_HTML, OUT_PDF)

    print("CHANGES:")
    for i, c in enumerate(changes, 1):
        print(f"{i}. {c}")
    print(f"MD:  {OUT_MD}")
    print(f"HTML:{OUT_HTML}")
    print(f"PDF: {OUT_PDF}")
    print(f"PDF_SIZE: {OUT_PDF.stat().st_size}")


if __name__ == "__main__":
    main()

